const body=document.querySelector("body");let links=body.getElementsByTagName("a");for(let e=0,t=links.length;e<t;e++)links[e].hostname!=window.location.hostname&&(links[e].target="_blank",links[e].rel="noopener");const nav=document.querySelector(".site-head__nav"),head=document.querySelector(".site-head__inner"),button=head.querySelector(".nav-burger"),siteOverlay=body.querySelector(".site-overlay");button.addEventListener("click",e=>{const t=button.getAttribute("aria-expanded")==="false";button.setAttribute("aria-expanded",t),nav.setAttribute("aria-expanded",t),t?body.classList.add("navOpen"):body.classList.remove("navOpen")}),body.addEventListener("keyup",e=>{e.code==="Escape"&&(button.setAttribute("aria-expanded",!1),nav.setAttribute("aria-expanded",!1),body.classList.remove("navOpen"),button.focus())}),siteOverlay.addEventListener("click",e=>{button.setAttribute("aria-expanded",!1),nav.setAttribute("aria-expanded",!1),body.classList.remove("navOpen"),button.focus()})